pub fn generate_personalized_emails(
    email_list: &str,
    name_list: &str,
    job_title_list: &str,
) -> Vec<Email> {
    let email_list = email_list.split(",");
    let name_list = name_list.split(",");
    let job_title_list = job_title_list.split(",");

    let mut emails = Vec::new();

    for (email, name, job_title) in email_list.zip(name_list.zip(job_title_list)) {
        let personalized_message = format!("Dear {},", name);
        let campaign_donation_request = format!(
            "I hope you can help me out with a small donation to help me win the election. I need all the help I can get to make sure we can keep America great! Thank you for your support.",
        );

        let sent_email = false;

        emails.push(Email {
            email,
            name,
            job_title,
            personalized_message,
            campaign_donation_request,
            sent_email,
        });
    }

    emails
